-- DVR CHAPTERS — VIRTUAL VIEWS OVER THE PER-SEGMENT LEDGER
-- A chapter is a (start_ms, end_ms) slice of a DVR artifact's ledger
-- rendered as an HLS manifest. Chapters are virtual: their identity is
-- derived from artifact + mode + range, their manifests are generated by
-- Foghorn from foghorn.dvr_segments and materialized in S3.
--
-- Two manifest shapes:
--   active (is_current=true):  EVENT-typed, no #EXT-X-ENDLIST, polled by readers
--   closed (is_current=false): VOD-typed, has #EXT-X-ENDLIST, fixed bounded playlist
--
-- The sidecar never writes chapter manifests; Foghorn owns archive playlists.
--
-- See: docs/architecture/dvr-continuous-archive.md

CREATE TABLE IF NOT EXISTS foghorn.dvr_chapters (
    chapter_id        VARCHAR(32) PRIMARY KEY,
    artifact_hash     VARCHAR(32) NOT NULL REFERENCES foghorn.artifacts(artifact_hash) ON DELETE CASCADE,
    mode              VARCHAR(32) NOT NULL,
        -- window_sized_chapters : sequential fixed-length chunks of size
        --                         tier.MaxWindowSeconds since started_at
        -- fixed_interval        : UTC-only interval_seconds buckets anchored at unix epoch 0
        -- explicit_range        : caller-supplied range; no recurrence semantics
    interval_seconds  INTEGER,                       -- NULL for window_sized_chapters and explicit_range
    start_ms          BIGINT NOT NULL,
    end_ms            BIGINT NOT NULL,
    is_current        BOOLEAN NOT NULL DEFAULT false,
    manifest_s3_key   TEXT,
    materialized_at   TIMESTAMPTZ,
    last_rebuilt_at   TIMESTAMPTZ,
    segment_count     INTEGER NOT NULL DEFAULT 0,
    has_gaps          BOOLEAN NOT NULL DEFAULT false,
    created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT chk_foghorn_dvr_chapters_mode CHECK (mode IN (
        'window_sized_chapters', 'fixed_interval', 'explicit_range'
    )),
    CONSTRAINT chk_foghorn_dvr_chapters_range CHECK (end_ms > start_ms)
);

CREATE INDEX IF NOT EXISTS idx_foghorn_dvr_chapters_artifact
    ON foghorn.dvr_chapters(artifact_hash, start_ms);
CREATE INDEX IF NOT EXISTS idx_foghorn_dvr_chapters_unmaterialized
    ON foghorn.dvr_chapters(artifact_hash) WHERE manifest_s3_key IS NULL;
CREATE INDEX IF NOT EXISTS idx_foghorn_dvr_chapters_current
    ON foghorn.dvr_chapters(artifact_hash) WHERE is_current = true;
-- Overlap invalidation: when a late lost_local segment lands, find materialized
-- chapters whose range overlaps the segment so their cached manifests can be
-- flagged has_gaps=true and rebuilt on the next sweep tick.
CREATE INDEX IF NOT EXISTS idx_foghorn_dvr_chapters_overlap
    ON foghorn.dvr_chapters(artifact_hash, end_ms, start_ms)
    WHERE manifest_s3_key IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_foghorn_dvr_chapters_dirty
    ON foghorn.dvr_chapters(created_at, chapter_id)
    WHERE manifest_s3_key IS NOT NULL AND last_rebuilt_at IS NULL;

-- ARTIFACT POLICY SNAPSHOT (DVR-only columns)
-- Captured at DVR start so finalization months later applies the same policy
-- even if the tenant's tier has changed mid-stream.
--   dvr_window_seconds   : resolved live DVR window (Mist targetAge)
--   dvr_chapter_mode     : default chapter mode for the sweeper to materialize
--   dvr_chapter_interval : interval_seconds for fixed_interval mode
--   dvr_retention_days   : tier policy snapshot; FinalizeDVR computes
--                          retention_until = ended_at + dvr_retention_days*24h
--   dvr_chapter_backfill_complete : terminal chapter index has been fully
--                                   materialized through ended_at

ALTER TABLE foghorn.artifacts
    ADD COLUMN IF NOT EXISTS dvr_window_seconds   INTEGER,
    ADD COLUMN IF NOT EXISTS dvr_chapter_mode     VARCHAR(32),
    ADD COLUMN IF NOT EXISTS dvr_chapter_interval INTEGER,
    ADD COLUMN IF NOT EXISTS dvr_retention_days   INTEGER,
    ADD COLUMN IF NOT EXISTS dvr_chapter_backfill_complete BOOLEAN NOT NULL DEFAULT false;

CREATE INDEX IF NOT EXISTS idx_foghorn_artifacts_dvr_backfill_pending
    ON foghorn.artifacts(ended_at, artifact_hash)
    WHERE artifact_type = 'dvr'
      AND status IN ('completed', 'completed_partial', 'failed', 'ready')
      AND ended_at IS NOT NULL
      AND dvr_chapter_mode IS NOT NULL
      AND dvr_chapter_mode != ''
      AND dvr_chapter_backfill_complete = false;
